from llama_index.core import StorageContext, load_index_from_storage
from pathlib import Path

INDEX_DIR = Path('./storage')

class AutoRefreshIndex:
    def __init__(self, index_dir):
        self.index_dir = Path(index_dir)
        self.last_docs_hash = None

    def needs_refresh(self, docs):
        current_hash = hash(tuple(sorted([doc.text for doc in docs])))
        return current_hash != self.last_docs_hash

    def get_query_engine(self, docs):
        if not self.index_dir.exists() or self.needs_refresh(docs):
            print('🔄 Rebuilding index...')
            index = VectorStoreIndex.from_documents(docs)
            index.storage_context.persist(persist_dir=str(self.index_dir))
            self.last_docs_hash = hash(tuple(sorted([doc.text for doc in docs])))
        else:
            storage_context = StorageContext.from_defaults(persist_dir=str(self.index_dir))
            index = load_index_from_storage(storage_context)

        return index.as_query_engine()

